import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError

def create_topic(admin_client, topic_name, num_partitions, replication_factor):
    new_topic = NewTopic(
        name=topic_name,
        num_partitions=num_partitions,
        replication_factor=replication_factor
    )
    try:
        admin_client.create_topics(new_topics=[new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully.")
    except TopicAlreadyExistsError:
        print(f"Topic '{topic_name}' already exists.")
    except Exception as e:
        print(f"Failed to create topic '{topic_name}': {e}")

def configure_topic(admin_client, topic_name, configs):
    config_resources = [ConfigResource(ConfigResourceType.TOPIC, topic_name, configs=configs)]
    try:
        admin_client.alter_configs(config_resources)
        print(f"Topic '{topic_name}' configured successfully.")
    except Exception as e:
        print(f"Failed to configure topic '{topic_name}': {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration Script")
    parser.add_argument("--broker", required=True, help="Kafka broker address")
    parser.add_argument("--create-topic", help="Name of the topic to create")
    parser.add_argument("--partitions", type=int, default=1, help="Number of partitions for the new topic")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor for the new topic")
    parser.add_argument("--configure-topic", help="Name of the topic to configure")
    parser.add_argument("--configs", nargs='*', metavar="KEY=VALUE", help="Topic configuration as key-value pairs")

    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.broker)

    if args.create_topic:
        create_topic(admin_client, args.create_topic, args.partitions, args.replication_factor)

    if args.configure_topic and args.configs:
        configs = {k: v for k, v in (conf.split('=') for conf in args.configs)}
        configure_topic(admin_client, args.configure_topic, configs)

    admin_client.close()

if __name__ == "__main__":
    main()